/* PixelPlay Design System — Colors & Typography Tokens
   Brand: PixelPlay by PixelPaws Labs
   Canvas: 1280×720px (Windows desktop app)
   ─────────────────────────────────────────────────── */

@import url('https://fonts.googleapis.com/css2?family=Nunito:wght@400;500;600;700&family=Inter:wght@400;500;600;700&display=swap');

/* NOTE: Segoe UI Variable is the production font (Windows built-in).
   Nunito is used as a Google Fonts substitute for cross-platform rendering.
   Inter is used for nav pill labels and Phase Mode branding — exact match. */

:root {

  /* ── ACCENT / BRAND ── */
  --color-accent:           #B3A7FF;           /* rgb(179,167,255) — main lavender purple */
  --color-accent-strong:    rgb(147, 129, 255); /* deeper purple, action label values */
  --color-accent-dim:       rgba(147,129,255,0.85); /* subtle accent fills */
  --color-accent-muted:     rgba(179,167,255,0.3);  /* toggle track active */
  --color-accent-bg:        rgb(239, 237, 248);  /* nav pill background, lavender tint */

  /* ── FOREGROUND / TEXT ── */
  --color-fg-1:             rgb(34, 34, 34);   /* primary text — near-black */
  --color-fg-2:             rgb(161, 161, 161); /* secondary / caption — medium grey */
  --color-fg-3:             rgb(131, 118, 211); /* action value labels — purple-grey */
  --color-fg-4:             rgb(195, 195, 195); /* muted text / disabled */
  --color-fg-dark:          rgb(1, 0, 1);       /* near-black fill */

  /* ── SURFACES ── */
  --color-surface-card:     rgba(255,255,255,0.5);  /* standard glass card */
  --color-surface-sidebar:  rgba(255,255,255,0.2);  /* sidebar/panel background */
  --color-surface-nav:      rgb(239, 237, 248);     /* nav pill container */
  --color-surface-overlay:  rgba(0,0,0,0.25);       /* sidebar backdrop overlay */
  --color-surface-white:    rgb(255,255,255);        /* solid white (selected pill, etc) */

  /* ── BORDERS ── */
  --color-border-card:      rgba(255,255,255,0.4);  /* card/nav border */
  --color-border-subtle:    rgba(201,192,255,0.5);  /* subtle purple tint border */
  --color-border-strong:    rgba(255,255,255,0.5);  /* stronger white border */

  /* ── STATUS / SEMANTIC ── */
  --color-danger:           rgb(255, 80, 80);   /* error, conflict state */
  --color-danger-strong:    rgb(255, 4, 4);     /* stronger red */
  --color-success:          rgb(0, 180, 100);   /* connected (green dot) — approx */

  /* ── BACKGROUND ── */
  --color-bg-fallback: linear-gradient(135deg, #1a1a2e 0%, #16213e 50%, #0f3460 100%);
  --color-bg-light:    rgb(255,255,255);         /* used in mockups */

  /* ── TYPOGRAPHY ── */

  /* Font stacks */
  --font-primary:   'Nunito', 'Segoe UI Variable', 'Segoe UI', system-ui, sans-serif;
  --font-secondary: 'Inter', sans-serif;

  /* Font sizes */
  --font-size-display:   86px;   /* Phase Mode hero text */
  --font-size-title:     28px;   /* Page title */
  --font-size-heading:   20px;   /* Section header */
  --font-size-label-lg:  16px;   /* Large label */
  --font-size-body:      14px;   /* Card label, body text */
  --font-size-caption:   12px;   /* Secondary text, nav labels */
  --font-size-micro:     10px;   /* Inline micro labels */
  --font-size-nano:       9px;   /* Smallest labels */

  /* Font weights */
  --font-weight-regular:   400;
  --font-weight-medium:    500;
  --font-weight-semibold:  600;
  --font-weight-bold:      700;

  /* Line heights */
  --line-height-tight:   1;
  --line-height-snug:    1.2;
  --line-height-body:    1.5;
  --line-height-ui:      20px;   /* Standard UI row height */
  --line-height-caption: 16px;   /* Caption row height */

  /* ── SPACING ── */
  --space-1:   4px;
  --space-2:   6px;
  --space-3:   10px;
  --space-4:   15px;
  --space-5:   16px;
  --space-6:   20px;
  --space-7:   22px;
  --space-8:   27px;

  /* ── CORNER RADII ── */
  --radius-sm:    10px;  /* button tag chip */
  --radius-md:    16px;  /* sidebar panels */
  --radius-lg:    20px;  /* cards, nav pill, accent buttons */
  --radius-full:  999px; /* fully round pills */

  /* ── BLUR ── */
  --blur-card:    blur(4px);
  --blur-sidebar: blur(20px) saturate(120%);

  /* ── SHADOW ── */
  --shadow-pill-inner: inset 0px 0px 7.1px 0px rgba(255,255,255,0.4);
  --shadow-overlay:    0px 0px 0px 9999px rgba(0,0,0,0.25);

  /* ── ANIMATION ── */
  --duration-screen:  400ms;
  --duration-sidebar: 300ms;
  --duration-pill:    500ms;
  --duration-stagger-card:   200ms;
  --duration-stagger-item:   150ms;
  --easing-default:   ease;
  --easing-spring:    cubic-bezier(0.34, 1.56, 0.64, 1);

  /* ── LAYOUT ── */
  --canvas-width:   1280px;
  --canvas-height:  720px;
  --titlebar-height: 32px;
  --sidebar-width:  433px;
  --navbar-height:   40px;
  --nav-pill-width: 320px;
}

/* ── SEMANTIC ELEMENT STYLES ── */

h1 {
  font-family: var(--font-primary);
  font-size: var(--font-size-title);
  font-weight: var(--font-weight-semibold);
  line-height: var(--line-height-snug);
  color: var(--color-fg-1);
  margin: 0;
}

h2 {
  font-family: var(--font-primary);
  font-size: var(--font-size-heading);
  font-weight: var(--font-weight-semibold);
  line-height: var(--line-height-snug);
  color: var(--color-fg-1);
  margin: 0;
}

h3 {
  font-family: var(--font-primary);
  font-size: var(--font-size-body);
  font-weight: var(--font-weight-semibold);
  line-height: var(--line-height-ui);
  color: var(--color-fg-1);
  margin: 0;
}

p, .body {
  font-family: var(--font-primary);
  font-size: var(--font-size-body);
  font-weight: var(--font-weight-regular);
  line-height: var(--line-height-body);
  color: var(--color-fg-1);
  margin: 0;
}

.caption {
  font-family: var(--font-primary);
  font-size: var(--font-size-caption);
  font-weight: var(--font-weight-regular);
  line-height: var(--line-height-caption);
  color: var(--color-fg-2);
}

.label-action {
  font-family: var(--font-primary);
  font-size: var(--font-size-micro);
  font-weight: var(--font-weight-regular);
  line-height: var(--line-height-body);
  color: var(--color-fg-3);
}

code, .mono {
  font-family: 'Consolas', 'Cascadia Code', monospace;
  font-size: var(--font-size-caption);
}

/* ── UTILITY CLASSES ── */

.glass-card {
  background: var(--color-surface-card);
  backdrop-filter: var(--blur-card);
  border-radius: var(--radius-lg);
}

.glass-sidebar {
  background: var(--color-surface-sidebar);
  backdrop-filter: var(--blur-sidebar);
  border: 1px solid var(--color-border-card);
  border-radius: var(--radius-md);
}

.glass-nav {
  background: var(--color-surface-nav);
  border: 1px solid var(--color-border-card);
  border-radius: var(--radius-full);
}

.pill-selected {
  background: var(--color-surface-white);
  border: 1px solid var(--color-surface-white);
  box-shadow: var(--shadow-pill-inner);
  border-radius: var(--radius-full);
}

.pill-accent {
  background: var(--color-accent);
  border: 1px solid var(--color-surface-white);
  box-shadow: var(--shadow-pill-inner);
  border-radius: var(--radius-full);
  color: var(--color-surface-white);
}

.button-tag {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  height: 20px;
  border-radius: var(--radius-sm);
  background: var(--color-surface-white);
  font-family: var(--font-primary);
  font-size: var(--font-size-micro);
  font-weight: var(--font-weight-bold);
  color: rgba(0,0,0,0.9);
}

// NavBar.jsx — PixelPlay nav bar component
const { useState } = React;

function PixelNavBar({ screen, setScreen }) {
  const [hovered, setHovered] = useState(null);

  const navItems = [
    { id: 'home', label: 'Home', icon: HomeIcon },
    { id: 'mouse', label: 'Mouse', icon: MouseIcon },
    { id: 'joystick', label: 'Joystick', icon: JoystickIcon },
  ];

  return (
    <div style={{
      display: 'flex', alignItems: 'center', justifyContent: 'space-between',
      width: '100%', height: 40,
    }}>
      {/* Logo */}
      <div style={{ display:'flex', alignItems:'center', gap:10 }}>
        <img src="../../assets/icons/logo-union.svg" width={16} height={16} alt="PixelPlay" style={{filter:'brightness(0)'}}/>
        <span style={{ fontFamily:"'Nunito',sans-serif", fontSize:14, fontWeight:700, color:'rgb(34,34,34)' }}>Pixelplay</span>
      </div>

      {/* Nav pill */}
      <div style={{
        display:'flex', alignItems:'center',
        background:'rgb(239,237,248)',
        border:'1px solid rgba(255,255,255,0.4)',
        borderRadius:20, height:40, padding:'3px',
        position:'relative', gap:2,
      }}>
        {navItems.map(item => {
          const isSelected = screen === item.id;
          return (
            <div
              key={item.id}
              onClick={() => setScreen(item.id)}
              onMouseEnter={() => setHovered(item.id)}
              onMouseLeave={() => setHovered(null)}
              style={{
                display:'flex', alignItems:'center', justifyContent:'center',
                gap:5, height:34, borderRadius:17, cursor:'pointer',
                padding: (isSelected || hovered === item.id) ? '0 14px' : '0 12px',
                minWidth:40,
                background: isSelected ? 'white' : 'transparent',
                boxShadow: isSelected ? 'inset 0 0 7px rgba(255,255,255,0.4)' : 'none',
                transition: 'all 300ms cubic-bezier(0.34,1.56,0.64,1)',
                color: 'rgb(34,34,34)',
              }}
            >
              <item.icon size={16} />
              {(isSelected || hovered === item.id) && (
                <span style={{
                  fontFamily:"'Inter',sans-serif", fontSize:12,
                  whiteSpace:'nowrap', overflow:'hidden',
                  maxWidth: 60,
                  transition:'max-width 200ms ease',
                }}>
                  {item.label}
                </span>
              )}
            </div>
          );
        })}

        {/* Phase pill (accent) */}
        <div style={{
          display:'flex', alignItems:'center', gap:6,
          height:34, borderRadius:17, padding:'0 14px',
          background:'rgb(179,167,255)',
          border:'1px solid white',
          boxShadow:'inset 0 0 7px rgba(255,255,255,0.4)',
          cursor:'pointer',
        }}>
          <PhaseIcon size={14} color="white" />
          <span style={{ fontFamily:"'Inter',sans-serif", fontSize:12, color:'white' }}>Phase</span>
        </div>
      </div>

      {/* Side icons */}
      <div style={{ display:'flex', alignItems:'center', gap:4 }}>
        {[ProfileIcon, BellIcon, SettingsIcon].map((Icon, i) => (
          <div key={i} style={{
            width:32, height:32, borderRadius:16,
            display:'flex', alignItems:'center', justifyContent:'center',
            cursor:'pointer', color:'rgb(34,34,34)',
          }}>
            <Icon size={17} />
          </div>
        ))}
      </div>
    </div>
  );
}

