// Card.jsx — PixelPlay glassmorphism card component

function GlassCard({ children, style, onClick }) {
  return (
    <div onClick={onClick} style={{
      background: 'rgba(255,255,255,0.5)',
      backdropFilter: 'blur(4px)',
      borderRadius: 20,
      position: 'relative',
      overflow: 'hidden',
      cursor: onClick ? 'pointer' : 'default',
      ...style,
    }}>
      {children}
    </div>
  );
}

function ButtonTag({ label, bordered=false, style }) {
  return (
    <div style={{
      display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
      width: 20, height: 20, borderRadius: 10,
      background: bordered ? 'rgba(179,167,255,0.1)' : 'white',
      border: bordered ? '1px solid rgba(179,167,255,0.5)' : 'none',
      fontFamily: "'Nunito',sans-serif",
      fontSize: 10, fontWeight: 700, color: 'rgba(0,0,0,0.9)',
      flexShrink: 0,
      ...style,
    }}>
      {label}
    </div>
  );
}

function ConfigCard({ tag, name, action, extra, onClick, style }) {
  return (
    <GlassCard onClick={onClick} style={{ padding: '12px 16px', ...style }}>
      <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom: extra ? 8 : 0 }}>
        <ButtonTag label={tag} />
        <div>
          <div style={{ fontSize:14, fontWeight:600, color:'rgb(34,34,34)', lineHeight:'20px' }}>{name}</div>
          {action && <div style={{ fontSize:10, color:'rgb(131,118,211)' }}>{action}</div>}
        </div>
      </div>
      {extra && (
        <div style={{ display:'flex', flexDirection:'column', gap:4 }}>
          {extra.map(([label, val], i) => (
            <div key={i} style={{ display:'flex', justifyContent:'space-between', fontSize:10 }}>
              <span style={{ color:'rgba(0,0,0,0.9)' }}>{label}</span>
              <span style={{ color:'rgb(131,118,211)' }}>{val}</span>
            </div>
          ))}
        </div>
      )}
    </GlassCard>
  );
}

function StatCard({ title, sub, value, caption, icon, style }) {
  return (
    <GlassCard style={{ padding:'15px 18px', ...style }}>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:10 }}>
        <div>
          <div style={{ fontSize:14, fontWeight:600, color:'rgb(34,34,34)', lineHeight:'20px' }}>{title}</div>
          {sub && <div style={{ fontSize:12, color:'rgb(161,161,161)' }}>{sub}</div>}
        </div>
        {icon && <div style={{ color:'rgba(147,129,255,0.5)' }}>{icon}</div>}
      </div>
      <div style={{ fontSize:36, fontWeight:700, color:'rgb(179,167,255)', lineHeight:1 }}>{value}</div>
      {caption && <div style={{ fontSize:12, color:'rgb(179,167,255)', marginTop:4 }}>{caption}</div>}
    </GlassCard>
  );
}

Object.assign(window, { GlassCard, ButtonTag, ConfigCard, StatCard });

// Sidebar.jsx — PixelPlay sliding sidebar panel
const { useState, useEffect, useRef } = React;

function PixelSidebar({ data, onClose }) {
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    requestAnimationFrame(() => setVisible(true));
  }, []);

  const close = () => {
    setVisible(false);
    setTimeout(onClose, 300);
  };

  return (
    <>
      {/* Overlay */}
      <div onClick={close} style={{
        position:'absolute', inset:0, zIndex:20,
        background:'rgba(0,0,0,0.18)',
        opacity: visible ? 1 : 0,
        transition:'opacity 300ms ease',
      }}/>
      {/* Panel */}
      <div style={{
        position:'absolute', top:32, right:0, width:433, height:688,
        zIndex:30,
        background:'rgba(255,255,255,0.22)',
        backdropFilter:'blur(20px) saturate(120%)',
        borderLeft:'1px solid rgba(255,255,255,0.4)',
        transform: visible ? 'translateX(0)' : 'translateX(100%)',
        transition:'transform 300ms ease',
        display:'flex', flexDirection:'column',
        overflowY:'hidden',
      }}>
        {/* Header */}
        <div style={{
          padding:'20px 24px 16px',
          borderBottom:'1px solid rgba(255,255,255,0.3)',
          display:'flex', justifyContent:'space-between', alignItems:'center',
          flexShrink:0,
        }}>
          <div>
            <div style={{ fontSize:20, fontWeight:600, color:'rgb(34,34,34)' }}>{data.title}</div>
            {data.subtitle && <div style={{ fontSize:12, color:'rgb(161,161,161)', marginTop:2 }}>{data.subtitle}</div>}
          </div>
          <div onClick={close} style={{
            width:28, height:28, borderRadius:14,
            background:'rgba(255,255,255,0.5)',
            display:'flex', alignItems:'center', justifyContent:'center',
            cursor:'pointer', fontSize:13, color:'rgb(100,100,100)',
          }}>✕</div>
        </div>

        {/* Body — scrollable */}
        <div style={{ flex:1, overflowY:'auto', padding:'20px 24px' }}>
          <SidebarBody data={data} visible={visible} />
        </div>
      </div>
    </>
  );
}

function SidebarBody({ data, visible }) {
  const items = data.rows || [];

  return (
    <div style={{ display:'flex', flexDirection:'column', gap:6 }}>
      {data.sections ? data.sections.map((sec, si) => (
        <div key={si} style={{ marginBottom:16 }}>
          <div style={{
            fontSize:10, fontWeight:600, color:'rgb(161,161,161)',
            textTransform:'uppercase', letterSpacing:'0.05em', marginBottom:10,
          }}>{sec.label}</div>
          {sec.rows.map((row, ri) => (
            <SidebarRow key={ri} row={row} index={si*10+ri} visible={visible} />
          ))}
        </div>
      )) : items.map((row, i) => (
        <SidebarRow key={i} row={row} index={i} visible={visible} />
      ))}
    </div>
  );
}

function SidebarRow({ row, index, visible }) {
  return (
    <div style={{
      display:'flex', justifyContent:'space-between', alignItems:'center',
      padding:'8px 0',
      borderBottom:'1px solid rgba(179,167,255,0.12)',
      opacity: visible ? 1 : 0,
      transform: visible ? 'translateY(0)' : 'translateY(20px)',
      transition:`opacity 250ms ease ${index * 80}ms, transform 250ms ease ${index * 80}ms`,
    }}>
      <span style={{ fontSize:13, color:'rgba(0,0,0,0.85)' }}>{row.label}</span>
      {row.value && <span style={{ fontSize:12, color:'rgb(131,118,211)' }}>{row.value}</span>}
      {row.toggle !== undefined && <Toggle on={row.toggle} />}
      {row.conflict && (
        <div style={{ display:'flex', alignItems:'center', gap:4 }}>
          <svg width="11" height="11" viewBox="0 0 24 24" fill="rgb(255,80,80)">
            <path d="M12 2L1 21h22L12 2zm0 4l8.5 15h-17L12 6zm-1 4v5h2V10h-2zm0 7v2h2v-2h-2z"/>
          </svg>
          <span style={{ fontSize:10, color:'rgb(255,80,80)' }}>Conflict detected</span>
        </div>
      )}
    </div>
  );
}

function Toggle({ on: initialOn }) {
  const [on, setOn] = useState(initialOn);
  return (
    <div onClick={() => setOn(o => !o)} style={{
      width:38, height:22, borderRadius:11,
      background: on ? 'rgb(179,167,255)' : 'rgba(179,167,255,0.25)',
      position:'relative', cursor:'pointer',
      transition:'background 200ms',
    }}>
      <div style={{
        position:'absolute', top:3,
        left: on ? 'calc(100% - 19px)' : 3,
        width:16, height:16, borderRadius:8, background:'white',
        transition:'left 200ms cubic-bezier(0.34,1.56,0.64,1)',
      }}/>
    </div>
  );
}

Object.assign(window, { PixelSidebar });

// HomeScreen.jsx — PixelPlay home screen
